-- Migration 102: seed the AI Service Management I - AI (AISM-I) certification.
--
-- Files AISM-I under the EXISTING 'governance-service-management' program (sort_order 4,
-- already live, holding AIGRM-I) - no category founding. Stands up the full skeleton from
-- the LOCKED AISM-I_JTA_v1 (Grok 8.8/10, recommend lock):
--   certification row -> 6 domains -> 226 concepts -> 61 tasks (with KSAs) -> 227 task_concepts links.
--
-- cert id 66666666-... continues the repeating-digit convention (AIGRM 5555, AISM 6666).
-- Concept count 226 = 210 native + 16 AIGRM-I-bridge (bridge rows share slug + definition with
-- their AIGRM-I siblings). ai-service-incident is ONE row (tasks 3.5 and 5.9), merged definition,
-- linked to both -> that single within-cert reuse is why links (227) exceed concepts (226).
-- (The JTA summary line's 220/205/15 is a stale pre-final count; the authoritative task/concept
--  tables specify 226/210/16, matched here and confirmed against the 61 authored lessons.)
--
-- exam_blueprint is set AFTER tasks, computed from public.v_cognitive_profile (migration 097),
-- never transcribed - the invariant-17-safe order. status='draft', is_published=false.
--
-- FREQUENCY mapping: JTA Freq H->weekly, M->occasional (the JTA uses only H and M). This is the
-- one soft-metadata modeling choice; adjust if cross-cert alignment with AIGRM-I is preferred.
--
-- Idempotent: SECTION 1 wipes ONLY this cert's children (scoped to 6666...), then reseeds.
-- Editor-first: run top-to-bottom in the SQL Editor, then commit this file. ASCII-only, dollar-quoted.
-- =====================================================================
-- SECTION 1 - Certification (upsert by fixed id). Category already exists; do NOT found it.
-- =====================================================================
insert into certifications (
  id, code, name, provider, description,
  exam_duration_minutes, passing_score_pct, num_questions,
  difficulty_level, tier, is_published, category_slug, sort_order, status
)
values (
  '66666666-6666-6666-6666-666666666666',
  'AISM-I',
  $$Certidemy AI Service Management I - AI$$,
  'Certidemy',
  $$AI-era-native service-management certification. Validates that the holder can run and govern AI-augmented services responsibly - service value and co-creation, the value system and guiding principles, the service lifecycle and core management practices, AI-augmented operations (AIOps, predictive operations, virtual agents, agentic automation, and human oversight), governing AI in service, and the experience, trust, and sustainability dimensions of service value - with AI treated as first-class where it genuinely changes the work. Built on field-standard service-management knowledge in Certidemy's own words and structure; designed to the ISO/IEC 17024 framework, audit-ready by design. Not presented as, and does not imply it is, ITIL or any third-party program.$$,
  120, 80.00, 80,
  1, 1, false, 'governance-service-management', 2, 'draft'
)
on conflict (id) do update set
  code = excluded.code, name = excluded.name, provider = excluded.provider,
  description = excluded.description, exam_duration_minutes = excluded.exam_duration_minutes,
  passing_score_pct = excluded.passing_score_pct, num_questions = excluded.num_questions,
  difficulty_level = excluded.difficulty_level, tier = excluded.tier,
  is_published = excluded.is_published, category_slug = excluded.category_slug,
  sort_order = excluded.sort_order, status = excluded.status, updated_at = now();
-- =====================================================================
-- SECTION 2 - Idempotency reset (scoped strictly to AISM-I)
-- =====================================================================
delete from task_concepts where task_id in (select id from tasks where certification_id = '66666666-6666-6666-6666-666666666666');
delete from tasks    where certification_id = '66666666-6666-6666-6666-666666666666';
delete from concepts where certification_id = '66666666-6666-6666-6666-666666666666';
delete from domains  where certification_id = '66666666-6666-6666-6666-666666666666';
-- =====================================================================
-- SECTION 3 - Domains (6). weight_pct sums to 100.
-- =====================================================================
insert into domains (certification_id, code, title, description, weight_pct, order_index)
values
  ('66666666-6666-6666-6666-666666666666','D1',$$Foundations of Digital Product & Service Management$$,$$The shared vocabulary and mental model the credential builds on: service, value co-creation, the parties in a service relationship, utility, warranty and experience, outcomes, and SLAs. Predominantly comprehension, making the applied domains legible. AI is woven in where a foundation genuinely changes; the sponsor, customer, and user roles stay clean.$$,12.5,1),
  ('66666666-6666-6666-6666-666666666666','D2',$$The Value System, Guiding Principles & Governance$$,$$The organizing system that turns opportunity and demand into value: the value-system components, the seven guiding principles (understood and applied), the continual-improvement model, and governance as direction and control. The most stable domain; AI enters only where it genuinely bears.$$,15.0,2),
  ('66666666-6666-6666-6666-666666666666','D3',$$The Service Lifecycle & Management Practices$$,$$The operating layer: the product-and-service lifecycle activities, value streams, and the core management practices - incident, problem, change, request, service level, and monitoring - plus one diagnostic task to root cause. AI enters at the practices it genuinely changes; supplier and AI-model-dependency management included.$$,17.5,3),
  ('66666666-6666-6666-6666-666666666666','D4',$$AI-Augmented Service Operations$$,$$The signature applied domain: how service operations change when AI is core. AIOps and event correlation, predictive and proactive operations, virtual agents at the service desk, intelligent and agentic automation, and human oversight of AI-driven service actions as a primary control. The richest, most applied domain.$$,27.5,4),
  ('66666666-6666-6666-6666-666666666666','D5',$$Governing AI in Service Management$$,$$The focused governance bridge to AIGRM-I: accountability when an agent acts on a live service, data quality and provenance for AIOps pipelines, transparency to users, over-automation risk, and how AI service governance plugs into the organization's broader AI governance. Deliberately bounded to complement, not duplicate, AIGRM-I.$$,15.0,5),
  ('66666666-6666-6666-6666-666666666666','D6',$$Experience, Trust & Sustainable Service$$,$$The human and responsible dimensions of service value: experience management and measuring it beyond technical service levels, trust and adoption as prerequisites for AI-service value, and sustainable service value including the compute and energy footprint of AI services.$$,12.5,6);
-- =====================================================================
-- SECTION 4 - Concepts (226 = 210 native + 16 bridge; ai-service-incident merged, one row)
-- =====================================================================
insert into concepts (certification_id, slug, name, description) values
  ('66666666-6666-6666-6666-666666666666','service-management-purpose',$$Service Management Purpose$$,$$coordinating people, process, and technology to deliver value reliably through services.$$),
  ('66666666-6666-6666-6666-666666666666','service-management-value',$$Service Management Value$$,$$why a disciplined approach beats ad-hoc delivery: consistency, reliability, accountability.$$),
  ('66666666-6666-6666-6666-666666666666','it-to-digital-shift',$$IT to Digital Shift$$,$$the field's move from managing IT services to managing digital products and services end-to-end.$$),
  ('66666666-6666-6666-6666-666666666666','ai-augmented-service-shift',$$AI Augmented Service Shift$$,$$the current wave of that same evolution: services with AI embedded in how they are run; the purpose (reliable value) is unchanged, the material is new.$$),
  ('66666666-6666-6666-6666-666666666666','service-definition',$$Service Definition$$,$$a means of enabling value co-creation by helping customers get outcomes without owning specific costs and risks.$$),
  ('66666666-6666-6666-6666-666666666666','product-definition',$$Product Definition$$,$$a configuration of resources, created by the organization, that will deliver value to consumers.$$),
  ('66666666-6666-6666-6666-666666666666','digital-product',$$Digital Product$$,$$a product delivered and consumed digitally, evolving continuously rather than shipped once.$$),
  ('66666666-6666-6666-6666-666666666666','digital-service',$$Digital Service$$,$$a service enabled by or delivered through digital technology, often software-defined.$$),
  ('66666666-6666-6666-6666-666666666666','product-vs-service',$$Product vs Service$$,$$a product is what is built and configured; a service is how its value is made available and consumed.$$),
  ('66666666-6666-6666-6666-666666666666','value-co-creation',$$Value Co Creation$$,$$value emerges from the active collaboration of provider and consumer, not from one-way delivery.$$),
  ('66666666-6666-6666-6666-666666666666','value-not-delivered',$$Value not Delivered$$,$$the provider cannot hand over value alone; the consumer's use and context complete it.$$),
  ('66666666-6666-6666-6666-666666666666','provider-contribution',$$Provider Contribution$$,$$what the provider brings: resources, capability, the service offering.$$),
  ('66666666-6666-6666-6666-666666666666','consumer-contribution',$$Consumer Contribution$$,$$what the consumer brings: their goals, context, and use that realize the outcome.$$),
  ('66666666-6666-6666-6666-666666666666','service-relationship',$$Service Relationship$$,$$the cooperation between a provider and a consumer across a service's life.$$),
  ('66666666-6666-6666-6666-666666666666','provider-consumer',$$Provider Consumer$$,$$the two primary parties; one supplies the service, one uses it.$$),
  ('66666666-6666-6666-6666-666666666666','sponsor-customer-user',$$Sponsor Customer User$$,$$the consumer-side roles: who authorizes budget, who defines requirements, who uses the service.$$),
  ('66666666-6666-6666-6666-666666666666','service-relationship-types',$$Service Relationship Types$$,$$the forms a relationship takes (e.g., basic provision, cooperation, partnership).$$),
  ('66666666-6666-6666-6666-666666666666','utility',$$Utility$$,$$fitness for purpose: what the service does (functionality).$$),
  ('66666666-6666-6666-6666-666666666666','warranty',$$Warranty$$,$$fitness for use: assurance the service performs (availability, capacity, security, continuity).$$),
  ('66666666-6666-6666-6666-666666666666','user-experience',$$User Experience$$,$$the whole of a user's interaction with, and perceptions of, a service.$$),
  ('66666666-6666-6666-6666-666666666666','fit-for-purpose-fit-for-use',$$Fit for Purpose Fit for Use$$,$$a service delivers value only when it is both useful and dependable.$$),
  ('66666666-6666-6666-6666-666666666666','output-vs-outcome',$$Output vs Outcome$$,$$an output is a deliverable; an outcome is the result the consumer actually needs.$$),
  ('66666666-6666-6666-6666-666666666666','cost-and-risk',$$Cost and Risk$$,$$value has two sides: costs/risks a service removes for the consumer, and costs/risks it imposes.$$),
  ('66666666-6666-6666-6666-666666666666','value-equation',$$Value Equation$$,$$value weighed as outcomes and experience against the costs and risks incurred.$$),
  ('66666666-6666-6666-6666-666666666666','service-quality',$$Service Quality$$,$$the degree to which a service meets expectations across utility, warranty, and experience.$$),
  ('66666666-6666-6666-6666-666666666666','service-level',$$Service Level$$,$$a defined, measured target for an aspect of a service.$$),
  ('66666666-6666-6666-6666-666666666666','sla',$$SLA$$,$$a documented agreement of expected service levels between provider and consumer.$$),
  ('66666666-6666-6666-6666-666666666666','sla-measurement-pitfall',$$SLA Measurement Pitfall$$,$$reporting every level "green" while the consumer is dissatisfied; measure the outcome, not just the metric.$$),
  ('66666666-6666-6666-6666-666666666666','ai-infused-service',$$AI Infused Service$$,$$a service whose behavior is partly produced by an AI model, changing how it is defined and assured.$$),
  ('66666666-6666-6666-6666-666666666666','co-creation-with-ai-service',$$Co Creation with AI Service$$,$$when the provider's contribution is a probabilistic model, the consumer co-creates value under uncertainty; assurance and expectation-setting change accordingly.$$),
  ('66666666-6666-6666-6666-666666666666','non-deterministic-output',$$Non Deterministic Output$$,$$an AI service may give different valid outputs for the same input; warranty shifts from promising a fixed result to assuring bounds - quality range, safety, and escalation.$$),
  ('66666666-6666-6666-6666-666666666666','ai-output-volume-trap',$$AI Output Volume Trap$$,$$AI can generate outputs (drafts, replies, classifications) at high volume, making activity look like achievement and sharpening the risk of counting outputs as outcomes.$$),
  ('66666666-6666-6666-6666-666666666666','ai-service-level',$$AI Service Level$$,$$a service level for a non-deterministic service defines acceptable quality ranges, safety limits, and human-escalation paths rather than a single guaranteed output.$$),
  ('66666666-6666-6666-6666-666666666666','ai-as-service-action',$$AI As Service Action$$,$$an AI-generated response is itself a service action for which the provider remains responsible; "the model did it" is not a defense.$$),
  ('66666666-6666-6666-6666-666666666666','service-that-drifts',$$Service That Drifts$$,$$an AI service's behavior can degrade over time as data and conditions shift, even with no code change.$$),
  ('66666666-6666-6666-6666-666666666666','provider-owns-ai-behavior',$$Provider Owns AI Behavior$$,$$the provider is answerable for what its AI service does and for detecting when it drifts; stability must be monitored, not assumed.$$),
  ('66666666-6666-6666-6666-666666666666','service-value-system',$$Service Value System$$,$$the model of how all the organization's components and activities work together to create value.$$),
  ('66666666-6666-6666-6666-666666666666','svs-components',$$SVS Components$$,$$the parts of the value system (principles, governance, the value chain, practices, continual improvement).$$),
  ('66666666-6666-6666-6666-666666666666','svs-inputs-outputs',$$SVS Inputs Outputs$$,$$opportunity and demand enter the system; value results.$$),
  ('66666666-6666-6666-6666-666666666666','guiding-principles',$$Guiding Principles$$,$$universal recommendations that guide an organization in all circumstances.$$),
  ('66666666-6666-6666-6666-666666666666','universal-guidance',$$Universal Guidance$$,$$the principles apply regardless of the framework, tool, or change being pursued.$$),
  ('66666666-6666-6666-6666-666666666666','principles-interact',$$Principles Interact$$,$$the principles reinforce one another and are used together, not in isolation.$$),
  ('66666666-6666-6666-6666-666666666666','focus-on-value',$$Focus On Value$$,$$everything done should link, directly or indirectly, to value for stakeholders.$$),
  ('66666666-6666-6666-6666-666666666666','start-where-you-are',$$Start Where You Are$$,$$assess and build on what already exists rather than starting over.$$),
  ('66666666-6666-6666-6666-666666666666','progress-iteratively-with-feedback',$$Progress Iteratively with Feedback$$,$$work in small increments, using feedback to adjust.$$),
  ('66666666-6666-6666-6666-666666666666','collaborate-and-promote-visibility',$$Collaborate and Promote Visibility$$,$$work across boundaries and make work and information visible.$$),
  ('66666666-6666-6666-6666-666666666666','think-and-work-holistically',$$Think and Work Holistically$$,$$no component works in isolation; consider the whole.$$),
  ('66666666-6666-6666-6666-666666666666','keep-it-simple-and-practical',$$Keep IT Simple and Practical$$,$$use the minimum steps to accomplish the objective; eliminate what adds no value.$$),
  ('66666666-6666-6666-6666-666666666666','optimize-and-automate',$$Optimize and Automate$$,$$optimize a process first, then automate what remains where it adds value.$$),
  ('66666666-6666-6666-6666-666666666666','principle-application',$$Principle Application$$,$$using a principle to reason toward a sound decision in a real situation.$$),
  ('66666666-6666-6666-6666-666666666666','principle-selection',$$Principle Selection$$,$$recognizing which principle a situation most calls for.$$),
  ('66666666-6666-6666-6666-666666666666','principle-tradeoffs',$$Principle Tradeoffs$$,$$principles can pull in different directions; applying them means weighing them.$$),
  ('66666666-6666-6666-6666-666666666666','ai-adoption-judgment',$$AI Adoption Judgment$$,$$using the principles (focus on value, keep it simple, start where you are) to decide whether AI genuinely serves the outcome or is being adopted for its own sake.$$),
  ('66666666-6666-6666-6666-666666666666','optimize-before-automate',$$Optimize Before Automate$$,$$automating an inefficient or broken process only scales the problem.$$),
  ('66666666-6666-6666-6666-666666666666','automation-candidacy',$$Automation Candidacy$$,$$judging whether a task is a good candidate for automation at all.$$),
  ('66666666-6666-6666-6666-666666666666','do-not-automate-a-broken-process',$$Do not Automate a Broken Process$$,$$fix or retire a flawed process before automating it.$$),
  ('66666666-6666-6666-6666-666666666666','ai-automation-judgment',$$AI Automation Judgment$$,$$deciding where AI-driven automation genuinely adds value versus where it adds risk.$$),
  ('66666666-6666-6666-6666-666666666666','ai-changes-automation-calculus',$$AI Changes Automation Calculus$$,$$AI expands the range of what can be automated and, at the same time, the range of failures that can occur without a visible error.$$),
  ('66666666-6666-6666-6666-666666666666','governance-definition',$$Governance Definition$$,$$the means by which an organization is directed and controlled.$$),
  ('66666666-6666-6666-6666-666666666666','governance-enabling',$$Governance Enabling$$,$$governance sets guardrails that enable delivery, not merely restrict it.$$),
  ('66666666-6666-6666-6666-666666666666','direct-monitor-evaluate',$$Direct Monitor Evaluate$$,$$the governing activities: set direction, monitor performance, evaluate results.$$),
  ('66666666-6666-6666-6666-666666666666','governance-vs-management',$$Governance vs Management$$,$$governance sets direction and holds accountable; management executes within it.$$),
  ('66666666-6666-6666-6666-666666666666','governing-body',$$Governing Body$$,$$the group accountable for the organization's direction and control.$$),
  ('66666666-6666-6666-6666-666666666666','delegated-authority',$$Delegated Authority$$,$$management operates under authority delegated by the governing body.$$),
  ('66666666-6666-6666-6666-666666666666','continual-improvement-model',$$Continual Improvement Model$$,$$a structured, repeatable approach to improving services and practices.$$),
  ('66666666-6666-6666-6666-666666666666','ci-steps',$$CI Steps$$,$$the model's stages, from vision through action to measurement and momentum.$$),
  ('66666666-6666-6666-6666-666666666666','ci-vision-to-action',$$CI Vision to Action$$,$$translating an improvement vision into concrete, measured steps.$$),
  ('66666666-6666-6666-6666-666666666666','ci-everyone-responsible',$$CI Everyone Responsible$$,$$continual improvement is a shared responsibility, not one team's job.$$),
  ('66666666-6666-6666-6666-666666666666','ci-application',$$CI Application$$,$$applying the model to a real improvement effort.$$),
  ('66666666-6666-6666-6666-666666666666','ci-common-failures',$$CI Common Failures$$,$$typical breakdowns: no baseline, no clear vision, no follow-through.$$),
  ('66666666-6666-6666-6666-666666666666','ci-baseline-measurement',$$CI Baseline Measurement$$,$$measuring the starting point so improvement can be shown.$$),
  ('66666666-6666-6666-6666-666666666666','ci-for-ai-services',$$CI for AI Services$$,$$an AI service is never "done": drift and changing data make continual measurement and improvement structural, not optional.$$),
  ('66666666-6666-6666-6666-666666666666','product-service-lifecycle',$$Product Service Lifecycle$$,$$the set of activities a product/service passes through from idea to ongoing support.$$),
  ('66666666-6666-6666-6666-666666666666','lifecycle-activities',$$Lifecycle Activities$$,$$discover, design, acquire, build, transition, operate, deliver, support (grouped in pairs).$$),
  ('66666666-6666-6666-6666-666666666666','iterative-not-sequential',$$Iterative not Sequential$$,$$activities recur and overlap; a service is continuously improved, not run once through a line.$$),
  ('66666666-6666-6666-6666-666666666666','discover-and-design',$$Discover and Design$$,$$understanding demand and shaping a service to meet it.$$),
  ('66666666-6666-6666-6666-666666666666','acquire-and-build',$$Acquire and Build$$,$$obtaining or constructing the components of a service.$$),
  ('66666666-6666-6666-6666-666666666666','transition-and-operate',$$Transition and Operate$$,$$moving a service into live use and running it.$$),
  ('66666666-6666-6666-6666-666666666666','deliver-and-support',$$Deliver and Support$$,$$providing the service to consumers and supporting its use.$$),
  ('66666666-6666-6666-6666-666666666666','lifecycle-activity-selection',$$Lifecycle Activity Selection$$,$$placing a real situation into the activity it belongs to.$$),
  ('66666666-6666-6666-6666-666666666666','management-practice',$$Management Practice$$,$$a set of organizational resources designed for performing work or accomplishing an objective.$$),
  ('66666666-6666-6666-6666-666666666666','practice-types',$$Practice Types$$,$$practices grouped by focus (general management, service management, and technical/product areas).$$),
  ('66666666-6666-6666-6666-666666666666','general-vs-service-practices',$$General vs Service Practices$$,$$broad management practices vs those specific to running services.$$),
  ('66666666-6666-6666-6666-666666666666','value-stream',$$Value Stream$$,$$a series of steps an organization uses to create and deliver products and services.$$),
  ('66666666-6666-6666-6666-666666666666','core-vs-enabling-value-stream',$$Core vs Enabling Value Stream$$,$$streams that directly produce value vs those that support them.$$),
  ('66666666-6666-6666-6666-666666666666','value-stream-purpose',$$Value Stream Purpose$$,$$modeling how work actually flows so it can be improved.$$),
  ('66666666-6666-6666-6666-666666666666','incident-management',$$Incident Management$$,$$restoring normal service operation as quickly as possible after an unplanned interruption.$$),
  ('66666666-6666-6666-6666-666666666666','problem-management',$$Problem Management$$,$$finding and removing the underlying causes of incidents.$$),
  ('66666666-6666-6666-6666-666666666666','incident-vs-problem',$$Incident vs Problem$$,$$an incident is the disruption; a problem is the cause of one or more incidents.$$),
  ('66666666-6666-6666-6666-666666666666','known-error',$$Known Error$$,$$a problem whose cause and workaround are documented.$$),
  ('66666666-6666-6666-6666-666666666666','workaround',$$Workaround$$,$$a means of reducing or eliminating an incident's impact without a full fix.$$),
  ('66666666-6666-6666-6666-666666666666','ai-service-incident',$$AI Service Incident$$,$$An incident caused by an AI service - covering both a degradation in output quality even when the system is technically available ('up' is not the same as 'working') and harm arising from an AI service action; either is a service incident the provider owns.$$),
  ('66666666-6666-6666-6666-666666666666','root-cause-analysis',$$Root Cause Analysis$$,$$systematically working from an incident's symptoms to the underlying cause that produces it.$$),
  ('66666666-6666-6666-6666-666666666666','contributing-vs-root-cause',$$Contributing vs Root Cause$$,$$separating factors that worsen or trigger an incident from the cause that actually produces it.$$),
  ('66666666-6666-6666-6666-666666666666','recurring-incident-signals-problem',$$Recurring Incident Signals Problem$$,$$repeated incidents are a signal of an unresolved underlying problem to be investigated.$$),
  ('66666666-6666-6666-6666-666666666666','change-enablement',$$Change Enablement$$,$$maximizing successful service changes by assessing and authorizing them appropriately.$$),
  ('66666666-6666-6666-6666-666666666666','change-types',$$Change Types$$,$$the categories a change can fall into, each with a different authorization path.$$),
  ('66666666-6666-6666-6666-666666666666','standard-normal-emergency-change',$$Standard Normal Emergency Change$$,$$pre-authorized/low-risk vs assessed vs expedited high-urgency changes.$$),
  ('66666666-6666-6666-6666-666666666666','change-authority',$$Change Authority$$,$$the person or group empowered to authorize a given change.$$),
  ('66666666-6666-6666-6666-666666666666','ai-model-change',$$AI Model Change$$,$$updating or retraining a model is a change that can alter service behavior unpredictably, so it needs assessment and authorization like any change, with extra care for unforeseeable effects.$$),
  ('66666666-6666-6666-6666-666666666666','service-request-management',$$Service Request Management$$,$$handling pre-defined, user-initiated requests smoothly and consistently.$$),
  ('66666666-6666-6666-6666-666666666666','service-desk',$$Service Desk$$,$$the single point of contact between the provider and its users.$$),
  ('66666666-6666-6666-6666-666666666666','request-vs-incident',$$Request vs Incident$$,$$a request is a normal, planned demand; an incident is an unplanned disruption.$$),
  ('66666666-6666-6666-6666-666666666666','service-level-management',$$Service Level Management$$,$$setting, monitoring, and reviewing targets for service performance.$$),
  ('66666666-6666-6666-6666-666666666666','monitoring-and-event-management',$$Monitoring and Event Management$$,$$observing services and managing the events (state changes) they emit.$$),
  ('66666666-6666-6666-6666-666666666666','event-alert-threshold',$$Event Alert Threshold$$,$$the level at which an observed event becomes an alert requiring attention.$$),
  ('66666666-6666-6666-6666-666666666666','monitoring-ai-services',$$Monitoring AI Services$$,$$an AI service must be monitored for behavior and output-quality drift over time, not only for up/down availability.$$),
  ('66666666-6666-6666-6666-666666666666','value-stream-mapping',$$Value Stream Mapping$$,$$visualizing the steps of a value stream to find delay, rework, and waste.$$),
  ('66666666-6666-6666-6666-666666666666','waste-identification',$$Waste Identification$$,$$spotting steps that add cost or delay without adding value.$$),
  ('66666666-6666-6666-6666-666666666666','flow-efficiency',$$Flow Efficiency$$,$$the proportion of end-to-end time in which value is actually being added.$$),
  ('66666666-6666-6666-6666-666666666666','ai-in-practices',$$AI in Practices$$,$$where AI is applied inside a management practice (e.g., triage, detection, assessment).$$),
  ('66666666-6666-6666-6666-666666666666','work-relocation',$$Work Relocation$$,$$AI moves *where* human effort is spent within a practice; it does not remove the practice.$$),
  ('66666666-6666-6666-6666-666666666666','human-accountability-retained',$$Human Accountability Retained$$,$$accountability for the outcome stays with a human even when AI performs a step.$$),
  ('66666666-6666-6666-6666-666666666666','ai-augmented-practice-boundary',$$AI Augmented Practice Boundary$$,$$the line between what the AI does and what a human must still decide inside a practice.$$),
  ('66666666-6666-6666-6666-666666666666','practice-transformed-not-replaced',$$Practice Transformed not Replaced$$,$$AI changes *how* a practice is performed (where effort and judgment sit), but the practice, its purpose, and its accountability remain.$$),
  ('66666666-6666-6666-6666-666666666666','supplier-management',$$Supplier Management$$,$$coordinating the third parties and providers a service depends on, so their contribution is reliable.$$),
  ('66666666-6666-6666-6666-666666666666','service-provider-dependency',$$Service Provider Dependency$$,$$a service's value can rest on providers the organization does not control; that dependency must be managed, not assumed.$$),
  ('66666666-6666-6666-6666-666666666666','ai-model-supplier-risk',$$AI Model Supplier Risk$$,$$an AI service often runs on a foundation model owned by an external provider, concentrating critical dependency in a supplier.$$),
  ('66666666-6666-6666-6666-666666666666','ai-vendor-lock-in',$$AI Vendor Lock in$$,$$deep reliance on one model provider makes switching costly and slow, weakening the organization's position.$$),
  ('66666666-6666-6666-6666-666666666666','model-changed-underneath',$$Model Changed Underneath$$,$$an external provider can update or deprecate a model, changing your service's behavior without your action; the dependency must be monitored and contracted for.$$),
  ('66666666-6666-6666-6666-666666666666','aiops',$$AIOps$$,$$applying AI/ML to operations data to detect, diagnose, and help resolve issues faster.$$),
  ('66666666-6666-6666-6666-666666666666','aiops-capabilities',$$AIOps Capabilities$$,$$correlation, anomaly detection, noise reduction, and assisted diagnosis over operational data.$$),
  ('66666666-6666-6666-6666-666666666666','aiops-vs-traditional-ops',$$AIOps vs Traditional Ops$$,$$pattern-learning across signals vs static thresholds and manual correlation.$$),
  ('66666666-6666-6666-6666-666666666666','event-correlation',$$Event Correlation$$,$$grouping related events so many alerts collapse into one actionable issue.$$),
  ('66666666-6666-6666-6666-666666666666','alert-noise-reduction',$$Alert Noise Reduction$$,$$suppressing redundant or low-value alerts so real issues are visible.$$),
  ('66666666-6666-6666-6666-666666666666','aiops-use-cases',$$AIOps Use Cases$$,$$where AIOps helps: monitoring, correlation, anomaly detection, capacity, triage.$$),
  ('66666666-6666-6666-6666-666666666666','signal-vs-noise',$$Signal vs Noise$$,$$distinguishing the meaningful indication from the surrounding alert clutter.$$),
  ('66666666-6666-6666-6666-666666666666','alert-storm',$$Alert Storm$$,$$a burst of many alerts from a single underlying fault.$$),
  ('66666666-6666-6666-6666-666666666666','root-signal-identification',$$Root Signal Identification$$,$$finding the one event that explains a flood of downstream alerts.$$),
  ('66666666-6666-6666-6666-666666666666','predictive-service-management',$$Predictive Service Management$$,$$using data to anticipate issues before they cause disruption.$$),
  ('66666666-6666-6666-6666-666666666666','proactive-vs-reactive',$$Proactive vs Reactive$$,$$acting on prediction and prevention rather than only responding to failures.$$),
  ('66666666-6666-6666-6666-666666666666','failure-prediction',$$Failure Prediction$$,$$forecasting a likely failure from patterns in operational data.$$),
  ('66666666-6666-6666-6666-666666666666','leading-indicators',$$Leading Indicators$$,$$early signals that precede an incident and enable prevention.$$),
  ('66666666-6666-6666-6666-666666666666','predictive-approach-fit',$$Predictive Approach Fit$$,$$judging whether a described operation is a good candidate for a predictive approach at all.$$),
  ('66666666-6666-6666-6666-666666666666','data-availability-for-prediction',$$Data Availability for Prediction$$,$$whether enough quality historical/operational data exists to predict reliably.$$),
  ('66666666-6666-6666-6666-666666666666','prediction-value-threshold',$$Prediction Value Threshold$$,$$the point at which prediction's benefit outweighs its cost and false-alarm burden.$$),
  ('66666666-6666-6666-6666-666666666666','recurring-incident-analysis',$$Recurring Incident Analysis$$,$$examining repeated incidents to find their shared driver.$$),
  ('66666666-6666-6666-6666-666666666666','predictive-control-fit',$$Predictive Control Fit$$,$$judging whether a predictive control would actually prevent a given pattern.$$),
  ('66666666-6666-6666-6666-666666666666','pattern-to-control',$$Pattern to Control$$,$$translating an identified pattern into a preventive control.$$),
  ('66666666-6666-6666-6666-666666666666','virtual-agent',$$Virtual Agent$$,$$an AI-driven conversational assistant that handles user interactions.$$),
  ('66666666-6666-6666-6666-666666666666','conversational-ai-service-desk',$$Conversational AI Service Desk$$,$$using conversational AI as a front door to the service desk.$$),
  ('66666666-6666-6666-6666-666666666666','deflection-rate',$$Deflection Rate$$,$$the share of contacts resolved without a human agent.$$),
  ('66666666-6666-6666-6666-666666666666','virtual-agent-limits',$$Virtual Agent Limits$$,$$where a virtual agent should stop: ambiguity, high stakes, low confidence.$$),
  ('66666666-6666-6666-6666-666666666666','escalation-boundary',$$Escalation Boundary$$,$$the defined point at which a virtual agent must hand off to a human.$$),
  ('66666666-6666-6666-6666-666666666666','confidence-threshold',$$Confidence Threshold$$,$$the certainty level below which the agent escalates rather than acts.$$),
  ('66666666-6666-6666-6666-666666666666','escalation-and-handoff',$$Escalation and Handoff$$,$$designed mechanisms for a human to take over or be brought in.$$),
  ('66666666-6666-6666-6666-666666666666','intelligent-automation',$$Intelligent Automation$$,$$automation that incorporates AI to handle variation and judgment, not just fixed rules.$$),
  ('66666666-6666-6666-6666-666666666666','scripted-vs-intelligent-automation',$$Scripted vs Intelligent Automation$$,$$deterministic scripts vs adaptive, model-assisted automation.$$),
  ('66666666-6666-6666-6666-666666666666','automation-in-workflows',$$Automation in Workflows$$,$$embedding automated steps within a service workflow.$$),
  ('66666666-6666-6666-6666-666666666666','agentic-service-workflow',$$Agentic Service Workflow$$,$$a workflow where an AI agent plans and takes multi-step service actions.$$),
  ('66666666-6666-6666-6666-666666666666','autonomy-levels',$$Autonomy Levels$$,$$how much an agent may decide and act without human approval.$$),
  ('66666666-6666-6666-6666-666666666666','action-reversibility',$$Action Reversibility$$,$$whether an action can be undone, a key input to how much autonomy is safe.$$),
  ('66666666-6666-6666-6666-666666666666','reduced-per-step-intervention',$$Reduced Per Step Intervention$$,$$the defining trait of an agentic workflow: a human no longer approves each step, distinguishing it from step-by-step automation.$$),
  ('66666666-6666-6666-6666-666666666666','bounded-autonomy',$$Bounded Autonomy$$,$$granting autonomy only within explicit, safe limits.$$),
  ('66666666-6666-6666-6666-666666666666','autonomy-decision-factors',$$Autonomy Decision Factors$$,$$the inputs that set a safe autonomy level: reversibility, stakes, confidence, oversight cost.$$),
  ('66666666-6666-6666-6666-666666666666','reversibility-and-stakes',$$Reversibility and Stakes$$,$$the two dominant factors: how undoable an action is, and how much is at risk if it is wrong.$$),
  ('66666666-6666-6666-6666-666666666666','compounding-actions',$$Compounding Actions$$,$$errors cascading and amplifying across an agent's multi-step chain.$$),
  ('66666666-6666-6666-6666-666666666666','multi-step-failure',$$Multi Step Failure$$,$$a failure that emerges from the sequence, not any single step.$$),
  ('66666666-6666-6666-6666-666666666666','blast-radius',$$Blast Radius$$,$$the scope of damage an autonomous action can cause before it is caught.$$),
  ('66666666-6666-6666-6666-666666666666','circuit-breaker-pattern',$$Circuit Breaker Pattern$$,$$a designed stop that halts an automated chain when conditions go out of bounds.$$),
  ('66666666-6666-6666-6666-666666666666','human-in-the-loop',$$Human in the Loop$$,$$a human reviews and approves within the decision loop before action.$$),
  ('66666666-6666-6666-6666-666666666666','human-on-the-loop',$$Human On the Loop$$,$$a human supervises and can intervene without approving each action.$$),
  ('66666666-6666-6666-6666-666666666666','oversight-in-service-actions',$$Oversight in Service Actions$$,$$applying human oversight specifically to AI actions taken on live services.$$),
  ('66666666-6666-6666-6666-666666666666','risk-based-oversight',$$Risk Based Oversight$$,$$matching the strength of oversight to the consequence of the action.$$),
  ('66666666-6666-6666-6666-666666666666','oversight-design',$$Oversight Design$$,$$designing where and how humans oversee a deployed system.$$),
  ('66666666-6666-6666-6666-666666666666','consequential-service-action',$$Consequential Service Action$$,$$an AI action with material impact on users or the business, warranting tighter oversight.$$),
  ('66666666-6666-6666-6666-666666666666','operation-degradation-diagnosis',$$Operation Degradation Diagnosis$$,$$reasoning from symptoms to the cause of a degraded AI operation.$$),
  ('66666666-6666-6666-6666-666666666666','model-drift',$$Model Drift$$,$$degradation of a deployed model's performance as conditions shift.$$),
  ('66666666-6666-6666-6666-666666666666','data-quality-in-ops',$$Data Quality in Ops$$,$$poor or shifted operational data as a driver of AIOps failure.$$),
  ('66666666-6666-6666-6666-666666666666','automation-failure-mode',$$Automation Failure Mode$$,$$the characteristic ways an automated/agentic operation goes wrong.$$),
  ('66666666-6666-6666-6666-666666666666','ai-governance-in-service',$$AI Governance in Service$$,$$governing AI specifically as it is used to run and deliver services.$$),
  ('66666666-6666-6666-6666-666666666666','why-govern-ai-services',$$Why Govern AI Services$$,$$AI service actions carry autonomy, scale, and opacity that ordinary service controls don't cover.$$),
  ('66666666-6666-6666-6666-666666666666','governance-gap',$$Governance Gap$$,$$the space traditional service controls leave uncovered once AI acts on services.$$),
  ('66666666-6666-6666-6666-666666666666','agentic-accountability',$$Agentic Accountability$$,$$who remains accountable when an autonomous agent takes action.$$),
  ('66666666-6666-6666-6666-666666666666','accountability-cannot-be-delegated',$$Accountability Cannot Be Delegated$$,$$accountability for AI-assisted work cannot be handed to the tool.$$),
  ('66666666-6666-6666-6666-666666666666','meaningful-human-control',$$Meaningful Human Control$$,$$retaining genuine control over consequential autonomous action.$$),
  ('66666666-6666-6666-6666-666666666666','data-quality-for-aiops',$$Data Quality for AIOps$$,$$AIOps and prediction are only as good as the operational data feeding them.$$),
  ('66666666-6666-6666-6666-666666666666','data-provenance',$$Data Provenance$$,$$knowing the origin and history of the data used.$$),
  ('66666666-6666-6666-6666-666666666666','garbage-in-garbage-out',$$Garbage in Garbage Out$$,$$flawed input data yields flawed predictions and automated decisions.$$),
  ('66666666-6666-6666-6666-666666666666','ai-interaction-disclosure',$$AI Interaction Disclosure$$,$$informing people when they are interacting with an AI system.$$),
  ('66666666-6666-6666-6666-666666666666','transparency-to-users',$$Transparency to Users$$,$$being clear with users about AI's role in a service and its limits.$$),
  ('66666666-6666-6666-6666-666666666666','virtual-agent-disclosure',$$Virtual Agent Disclosure$$,$$telling users they are dealing with a virtual agent, not a person.$$),
  ('66666666-6666-6666-6666-666666666666','over-automation-risk',$$Over Automation Risk$$,$$the risk created by automating decisions that should retain human judgment.$$),
  ('66666666-6666-6666-6666-666666666666','automation-bias',$$Automation Bias$$,$$the tendency to over-trust automated output and stop checking it.$$),
  ('66666666-6666-6666-6666-666666666666','human-check-necessity',$$Human Check Necessity$$,$$where a human review must remain regardless of automation maturity.$$),
  ('66666666-6666-6666-6666-666666666666','deskilling-risk',$$Deskilling Risk$$,$$losing human capability by automating away the work that builds it.$$),
  ('66666666-6666-6666-6666-666666666666','ai-governance-alignment',$$AI Governance Alignment$$,$$keeping AI service governance consistent with organizational AI policy.$$),
  ('66666666-6666-6666-6666-666666666666','enterprise-ai-governance-link',$$Enterprise AI Governance Link$$,$$connecting service-level AI governance to enterprise AI risk management.$$),
  ('66666666-6666-6666-6666-666666666666','defense-in-depth-governance',$$Defense in Depth Governance$$,$$using multiple instruments together for stronger, layered governance.$$),
  ('66666666-6666-6666-6666-666666666666','ai-service-monitoring',$$AI Service Monitoring$$,$$ongoing observation of an AI-driven service's real-world behavior.$$),
  ('66666666-6666-6666-6666-666666666666','what-to-monitor',$$What to Monitor$$,$$choosing the right signals: output quality, drift, confidence, escalation rate, user harm.$$),
  ('66666666-6666-6666-6666-666666666666','drift-and-degradation-signals',$$Drift and Degradation Signals$$,$$the observable indicators that a model or service is degrading over time.$$),
  ('66666666-6666-6666-6666-666666666666','harm-detection-signals',$$Harm Detection Signals$$,$$signals that an AI service action has caused, or is about to cause, harm to a user.$$),
  ('66666666-6666-6666-6666-666666666666','ai-incident-response',$$AI Incident Response$$,$$responding to failures and harms from AI-driven services.$$),
  ('66666666-6666-6666-6666-666666666666','improve-ai-services',$$Improve AI Services$$,$$feeding monitoring and incidents back into improving AI services over time.$$),
  ('66666666-6666-6666-6666-666666666666','feedback-to-improvement',$$Feedback to Improvement$$,$$closing the loop from what monitoring and incidents reveal to concrete service improvement.$$),
  ('66666666-6666-6666-6666-666666666666','harm-escalation',$$Harm Escalation$$,$$routing an AI-caused harm to the right responders quickly.$$),
  ('66666666-6666-6666-6666-666666666666','serious-incident-reporting',$$Serious Incident Reporting$$,$$escalating and reporting significant AI incidents.$$),
  ('66666666-6666-6666-6666-666666666666','rollback-and-remediation',$$Rollback and Remediation$$,$$reversing an AI action's effect and repairing the damage.$$),
  ('66666666-6666-6666-6666-666666666666','service-experience',$$Service Experience$$,$$the whole of how a user perceives and feels about interacting with a service, beyond whether it technically works.$$),
  ('66666666-6666-6666-6666-666666666666','experience-vs-performance',$$Experience vs Performance$$,$$a service can meet every technical target and still deliver a poor experience; the two are measured differently.$$),
  ('66666666-6666-6666-6666-666666666666','perception-and-value',$$Perception and Value$$,$$perceived value depends on experience, so experience is part of value, not a cosmetic extra.$$),
  ('66666666-6666-6666-6666-666666666666','experience-measurement',$$Experience Measurement$$,$$measuring service quality from the user's perspective: did they achieve their goal, and how did it feel.$$),
  ('66666666-6666-6666-6666-666666666666','outcome-based-metric',$$Outcome Based Metric$$,$$a measure of whether the user reached their intended outcome, not just whether a system was available.$$),
  ('66666666-6666-6666-6666-666666666666','beyond-technical-sla',$$Beyond Technical SLA$$,$$technical service levels can all be "green" while the user's experience is poor; experience needs its own measures (the generalization of the SLA "watermelon" pitfall).$$),
  ('66666666-6666-6666-6666-666666666666','experience-improvement',$$Experience Improvement$$,$$choosing a change that raises the user's perceived experience, not just a technical metric.$$),
  ('66666666-6666-6666-6666-666666666666','friction-identification',$$Friction Identification$$,$$spotting the points where a service frustrates or slows the user.$$),
  ('66666666-6666-6666-6666-666666666666','experience-design-choice',$$Experience Design Choice$$,$$selecting the design change that most improves how the service feels to use.$$),
  ('66666666-6666-6666-6666-666666666666','trust-in-ai-service',$$Trust in AI Service$$,$$users co-create value with an AI service only if they trust it enough to rely on it, and rely on it appropriately.$$),
  ('66666666-6666-6666-6666-666666666666','appropriate-trust',$$Appropriate Trust$$,$$calibrated trust: neither over-trusting a fallible AI nor under-trusting a useful one; both destroy value.$$),
  ('66666666-6666-6666-6666-666666666666','adoption-prerequisite',$$Adoption Prerequisite$$,$$an AI service delivers no value if users will not adopt it; adoption is a service outcome to be earned.$$),
  ('66666666-6666-6666-6666-666666666666','trust-transparency',$$Trust Transparency$$,$$being open about what the AI is, what it does well, and where it errs is what makes trust calibrated rather than blind.$$),
  ('66666666-6666-6666-6666-666666666666','building-appropriate-trust',$$Building Appropriate Trust$$,$$choosing actions (transparency, explainability, reliable escalation) that raise calibrated trust.$$),
  ('66666666-6666-6666-6666-666666666666','transparency-action',$$Transparency Action$$,$$disclosing AI use, confidence, and limits so users can judge when to rely on the service.$$),
  ('66666666-6666-6666-6666-666666666666','escalation-as-trust',$$Escalation As Trust$$,$$a visible, reliable path to a human raises trust in the AI by making its limits safe.$$),
  ('66666666-6666-6666-6666-666666666666','over-trust-correction',$$Over Trust Correction$$,$$designing against blind over-reliance, e.g., prompting users to verify high-stakes AI outputs.$$),
  ('66666666-6666-6666-6666-666666666666','sustainable-service',$$Sustainable Service$$,$$delivering service value without disproportionate environmental or social cost, now and over time.$$),
  ('66666666-6666-6666-6666-666666666666','triple-dimension-value',$$Triple Dimension Value$$,$$value has environmental and social dimensions alongside the economic one; sustainability weighs all three.$$),
  ('66666666-6666-6666-6666-666666666666','sustainability-in-value-system',$$Sustainability in Value System$$,$$sustainability is woven into how value is created, not treated as an isolated checklist.$$),
  ('66666666-6666-6666-6666-666666666666','ai-compute-footprint',$$AI Compute Footprint$$,$$running AI services consumes significant compute and energy, giving them a material environmental cost.$$),
  ('66666666-6666-6666-6666-666666666666','green-ai',$$Green AI$$,$$reducing the energy and resource cost of AI services through efficient models and operations.$$),
  ('66666666-6666-6666-6666-666666666666','efficiency-as-service-quality',$$Efficiency As Service Quality$$,$$compute efficiency is a service-management concern, not only a cost line: it affects sustainability and scalability.$$),
  ('66666666-6666-6666-6666-666666666666','sustainability-tradeoff',$$Sustainability Tradeoff$$,$$balancing a lower footprint against service quality, cost, and outcomes.$$),
  ('66666666-6666-6666-6666-666666666666','right-sizing-model',$$Right Sizing Model$$,$$using a model no larger than the task needs, cutting waste without hurting outcomes.$$),
  ('66666666-6666-6666-6666-666666666666','efficient-inference',$$Efficient Inference$$,$$operational choices (caching, batching, smaller models for simple cases) that cut compute per request.$$),
  ('66666666-6666-6666-6666-666666666666','sustainability-without-degradation',$$Sustainability Without Degradation$$,$$choosing the footprint reduction that preserves the user's outcome and experience.$$);
-- =====================================================================
-- SECTION 5 - Tasks (61). domain_id resolved by domain code. order_index global 1..61.
-- =====================================================================
insert into tasks (certification_id, domain_id, code, statement, criticality, frequency, bloom_level, is_exam_scope, is_simulation_candidate, knowledge, skills, abilities, order_index)
select '66666666-6666-6666-6666-666666666666', d.id, v.code, v.statement,
       v.criticality::criticality, v.frequency::task_frequency, v.bloom::bloom_level,
       true, false, v.knowledge, v.skills, v.abilities, v.order_index
from (values
  ('D1','1.1',$$Explain why service management exists and the problem it solves, and how the field's shift from IT to digital to AI-augmented services extends that same purpose.$$,'high','weekly','2_understand',false,$$Service management coordinates people, process, and technology to deliver value reliably; the shift from IT to digital to AI-augmented services extends that same purpose.$$,$$Explain the problem service management solves and place the AI-augmented shift on that continuum.$$,$$Sees disciplined design, not heroics, as the source of reliable value.$$,1),
  ('D1','1.2',$$Define the core terms - service, product, digital product, digital service - and recognize an AI-infused service as one whose behavior is partly produced by a model.$$,'high','weekly','2_understand',false,$$The definitions of service, product, digital product, and digital service, and what makes a service AI-infused (behavior partly produced by a model).$$,$$Classify a described offering among these terms and flag when it is AI-infused.$$,$$Precision with everyday words used as technical terms.$$,2),
  ('D1','1.3',$$Explain value co-creation - how value is jointly produced by provider and consumer, not delivered - and how it changes when the provider's contribution is a probabilistic AI model (co-creation under uncertainty).$$,'high','weekly','2_understand',false,$$Value is co-created by provider and consumer, not delivered; a probabilistic model shifts this into co-creation under uncertainty.$$,$$Identify each side's contribution and how AI changes expectation-setting and assurance.$$,$$Resists treating value as something handed over.$$,3),
  ('D1','1.4',$$Distinguish the parties and roles in a service relationship - provider, consumer, and the sponsor / customer / user roles. *(Foundation unchanged by AI - taught clean.)*$$,'medium','weekly','2_understand',false,$$The provider and consumer parties and the sponsor, customer, and user roles inside the consumer.$$,$$Assign the right role to an actor in a scenario.$$,$$Serves all roles, not only the loudest.$$,4),
  ('D1','1.5',$$Explain utility, warranty, and experience as the dimensions of a service's fitness - and how warranty changes for non-deterministic AI output, assuring a range of quality rather than an identical result.$$,'high','weekly','2_understand',false,$$Utility (fit for purpose), warranty (fit for use), and experience, and how warranty shifts to assuring bounds for non-deterministic AI output.$$,$$Match a described shortfall to utility, warranty, or experience, and adapt warranty for an AI service.$$,$$Holds that value needs both the right thing and dependable delivery.$$,5),
  ('D1','1.6',$$Explain outputs vs outcomes, and cost and risk as what a service removes and imposes - including why AI's ability to mass-produce outputs sharpens the risk of mistaking outputs for outcomes.$$,'high','occasional','2_understand',false,$$Outputs vs outcomes, the value equation of costs and risks removed vs imposed, and how AI mass-production sharpens the outputs-for-outcomes trap.$$,$$Separate output counts from outcomes and spot the AI volume trap.$$,$$Measures achievement by outcomes, not activity.$$,6),
  ('D1','1.7',$$Explain service quality, service levels, and SLAs as the agreement of expectation - and how a service level is written for an AI service, committing to quality bounds and escalation rather than identical output.$$,'high','weekly','2_understand',false,$$Service quality, service levels, and SLAs as the agreement of expectation, the measurement pitfall, and how an AI service level commits to bounds, safety, and escalation.$$,$$Write or judge a service level, including one for a non-deterministic AI service.$$,$$Distrusts green metrics that hide an unhappy consumer.$$,7),
  ('D1','1.8',$$Explain the provider's continuing accountability for an AI service's behavior - that an AI output is a service action the provider owns, and that AI services drift and must be monitored, not assumed stable.$$,'high','weekly','2_understand',false,$$An AI output is a service action the provider owns; AI services drift and must be monitored, not assumed stable.$$,$$Reject the-model-did-it and identify the monitoring an AI service needs.$$,$$Owns the behavior of the service continuously.$$,8),
  ('D2','2.1',$$Explain the components of a service value system and how they fit together.$$,'high','weekly','2_understand',false,$$The service value system and its components (principles, governance, value chain, practices, continual improvement), and how opportunity and demand become value.$$,$$Identify how the components combine to create value.$$,$$Sees the whole system, not isolated parts.$$,9),
  ('D2','2.2',$$Explain the purpose of the guiding principles as universal, framework-agnostic recommendations.$$,'medium','weekly','2_understand',false,$$The guiding principles as universal, framework-agnostic recommendations that interact.$$,$$Explain why principles outlast tools and are used together.$$,$$Reaches for durable principles over situational rules.$$,10),
  ('D2','2.3',$$Explain each of the seven guiding principles and what it recommends.$$,'high','weekly','2_understand',false,$$What each of the seven guiding principles recommends.$$,$$State and illustrate each principle in a service context.$$,$$Carries the principles into everyday decisions.$$,11),
  ('D2','2.4',$$Given a described situation - including a decision about whether and where to adopt AI - apply the appropriate guiding principle to choose a sound course of action.$$,'high','weekly','3_apply',false,$$Principle selection, application, and trade-offs, and using the principles to judge whether and where to adopt AI.$$,$$Read a situation for the principle it calls for and reason to a sound action, including AI-adoption decisions.$$,$$Lets value, not novelty, decide AI adoption.$$,12),
  ('D2','2.5',$$Apply "optimize and automate" to decide which service activities suit AI-driven automation and which must retain meaningful human judgment - recognizing that AI widens both what can be automated and what can fail silently.$$,'high','weekly','3_apply',false,$$Optimize before automate, automation candidacy, do-not-automate-a-broken-process, and how AI widens both what can be automated and what can fail silently.$$,$$Decide which activities suit AI automation and which must keep human judgment.$$,$$Matches the human check to the cost of a silent failure.$$,13),
  ('D2','2.6',$$Explain governance as the direction and control that enables service management.$$,'high','occasional','2_understand',false,$$Governance as the means by which an organization is directed and controlled through direct, monitor, and evaluate; it enables delivery.$$,$$Explain how governance sets enabling guardrails.$$,$$Sees governance as enabling, not merely restricting.$$,14),
  ('D2','2.7',$$Distinguish governance from management and from day-to-day operations.$$,'medium','occasional','2_understand',false,$$Governance sets direction and holds accountable; management executes under delegated authority; the governing body stays accountable.$$,$$Sort activities into governance or management.$$,$$Keeps direction-setting distinct from execution.$$,15),
  ('D2','2.8',$$Explain the continual improvement model and its steps - and why AI services in particular require continual improvement, because they drift and cannot be improved once and left.$$,'high','weekly','2_understand',false,$$The continual improvement model and its steps, that improvement is everyone's responsibility, and why AI services make continual improvement structural.$$,$$Walk the model's steps and explain why an AI service is never improved once and left.$$,$$Treats improvement as an ongoing habit, not a project.$$,16),
  ('D2','2.9',$$Given a described improvement effort, determine which continual-improvement step it skipped.$$,'high','occasional','3_apply',false,$$How to apply the improvement model as a diagnostic and its common failures (no baseline, no follow-through).$$,$$Read a stalled effort's symptoms and name the skipped step.$$,$$Diagnoses rather than blames when improvement fails.$$,17),
  ('D3','3.1',$$Explain the product-and-service lifecycle activities and that they are iterative, not sequential.$$,'high','weekly','2_understand',false,$$The lifecycle activities (discover/design, acquire/build, transition/operate, deliver/support) and that they are iterative, not sequential.$$,$$Describe the lifecycle and why it recurs rather than runs once.$$,$$Views a service as continuously improved, not shipped once.$$,18),
  ('D3','3.2',$$Given a described situation, determine which lifecycle activity it belongs to.$$,'high','weekly','3_apply',false,$$What each lifecycle activity covers.$$,$$Place a described situation into the lifecycle activity it belongs to.$$,$$Maps real work to the right stage.$$,19),
  ('D3','3.3',$$Explain what a management practice is and distinguish general vs service management practices.$$,'high','weekly','2_understand',false,$$What a management practice is and the distinction between general and service management practices.$$,$$Classify a practice by type.$$,$$Uses shared vocabulary precisely.$$,20),
  ('D3','3.4',$$Explain value streams - core and enabling - and their role in delivering a service.$$,'medium','occasional','2_understand',false,$$Value streams (core and enabling) and their role in delivering a service.$$,$$Explain how a value stream models the flow of work.$$,$$Thinks in end-to-end flow.$$,21),
  ('D3','3.5',$$Explain incident and problem management and select which applies - recognizing that a drop in AI output quality is itself an incident even when nothing is "down".$$,'high','weekly','3_apply',false,$$Incident vs problem management, known error and workaround, and that a drop in AI output quality is an incident even when nothing is down.$$,$$Select whether incident or problem management applies, including for AI output degradation.$$,$$Treats up and working as different things.$$,22),
  ('D3','3.6',$$Analyze a described recurring incident to identify its underlying problem (its root cause).$$,'high','occasional','4_analyze',false,$$Root-cause analysis, contributing vs root cause, and that recurring incidents signal an unresolved problem.$$,$$Analyze a recurring incident to its underlying problem.$$,$$Presses past symptoms to the real cause.$$,23),
  ('D3','3.7',$$Explain change enablement and select the appropriate change type - including treating an AI model update or retraining as a change whose effects are hard to predict and must be governed accordingly.$$,'high','weekly','3_apply',false,$$Change enablement, change types (standard, normal, emergency), change authority, and that an AI model update or retraining is a change with hard-to-predict effects.$$,$$Select the appropriate change type, including for an AI model update.$$,$$Governs model changes as carefully as any change.$$,24),
  ('D3','3.8',$$Explain service request management and the service desk as the point of engagement.$$,'medium','weekly','2_understand',false,$$Service request management, the service desk as point of engagement, and request vs incident.$$,$$Distinguish a request from an incident.$$,$$Keeps the user's point of contact in view.$$,25),
  ('D3','3.9',$$Explain service level management and monitoring & event management - including monitoring an AI service for drift and output-quality degradation, not just availability.$$,'medium','occasional','2_understand',false,$$Service level management, monitoring and event management, event and alert thresholds, and monitoring an AI service for drift, not just availability.$$,$$Explain what to monitor for an AI service beyond up and down.$$,$$Watches behavior, not only uptime.$$,26),
  ('D3','3.10',$$Given a described flow, determine an improvement using value-stream thinking (find the waste).$$,'high','occasional','3_apply',false,$$Value-stream mapping, waste identification, and flow efficiency.$$,$$Determine an improvement to a described flow using value-stream thinking.$$,$$Sees waste where others see busyness.$$,27),
  ('D3','3.11',$$Determine where AI shifts human effort inside a management practice (such as triage, detection, or assessment) while the purpose of the practice and human accountability for its outcome remain unchanged.$$,'high','weekly','3_apply',false,$$AI relocates human effort inside a practice (triage, detection, assessment) while purpose and human accountability remain; the practice is transformed, not replaced.$$,$$Locate where AI moves effort inside a practice without moving accountability.$$,$$Keeps accountability with the human as work relocates.$$,28),
  ('D3','3.12',$$Explain supplier and service-provider management, and the distinctive dependency risk of an AI service built on a model you do not own - lock-in, and a provider changing the model underneath you.$$,'high','weekly','2_understand',false,$$Supplier and service-provider management, and the dependency risk of an AI service built on a model you do not own (lock-in; a provider changing the model underneath you).$$,$$Identify the dependency risks of running a service on an external model.$$,$$Manages, rather than assumes, dependencies it does not control.$$,29),
  ('D4','4.1',$$Explain what AIOps is and how it changes service operations.$$,'high','weekly','2_understand',false,$$AIOps and how it changes service operations versus static thresholds and manual correlation.$$,$$Explain AIOps capabilities and where they apply.$$,$$Open to pattern-learning over fixed rules.$$,30),
  ('D4','4.2',$$Given a described operation, determine where AIOps adds value across monitoring, event correlation, and noise reduction.$$,'high','weekly','3_apply',false,$$Event correlation, alert-noise reduction, and AIOps use cases.$$,$$Determine where AIOps adds value in a described operation.$$,$$Targets AIOps where it earns its place.$$,31),
  ('D4','4.3',$$Analyze an alert flood to identify the underlying signal AIOps should surface.$$,'high','occasional','4_analyze',false,$$Signal vs noise, alert storms, and root-signal identification.$$,$$Analyze an alert flood to the underlying signal AIOps should surface.$$,$$Finds the one cause behind many alerts.$$,32),
  ('D4','4.4',$$Explain predictive and proactive service management.$$,'high','weekly','2_understand',false,$$Predictive service management, proactive vs reactive, failure prediction, and leading indicators.$$,$$Explain how prediction shifts operations from reactive to proactive.$$,$$Prefers preventing failures to responding to them.$$,33),
  ('D4','4.5',$$Given a described operation, determine whether a predictive approach fits.$$,'high','weekly','3_apply',false,$$Predictive-approach fit, data availability for prediction, and the prediction-value threshold.$$,$$Judge whether a described operation suits a predictive approach.$$,$$Applies prediction only where data and value justify it.$$,34),
  ('D4','4.6',$$Analyze a recurring-incident pattern to determine whether a predictive control would prevent it.$$,'high','occasional','4_analyze',false,$$Recurring-incident analysis, predictive-control fit, and translating a pattern into a control.$$,$$Determine whether a predictive control would prevent a recurring pattern.$$,$$Reasons from pattern to preventive control.$$,35),
  ('D4','4.7',$$Explain virtual agents and conversational AI at the service desk, and their limits.$$,'high','weekly','2_understand',false,$$Virtual agents and conversational AI at the service desk, deflection rate, and their limits.$$,$$Explain what a virtual agent handles and where it must stop.$$,$$Honest about where automation should hand off.$$,36),
  ('D4','4.8',$$Given a described user request handled by a virtual agent, determine whether the agent should resolve it or escalate to a human, based on the request's risk and the agent's confidence.$$,'high','weekly','3_apply',false,$$The escalation boundary, confidence threshold, and escalation and handoff design.$$,$$Decide whether a virtual agent should resolve or escalate based on risk and confidence.$$,$$Escalates when stakes or uncertainty demand a human.$$,37),
  ('D4','4.9',$$Explain intelligent automation and how it differs from traditional scripted automation.$$,'medium','weekly','2_understand',false,$$Intelligent automation and how it differs from scripted automation, and automation within workflows.$$,$$Distinguish intelligent from scripted automation in a scenario.$$,$$Matches the automation type to the variability of the work.$$,38),
  ('D4','4.10',$$Explain agentic workflows in service operations - how an AI agent plans and takes multi-step action with reduced per-step human intervention.$$,'high','weekly','2_understand',false,$$Agentic service workflows, autonomy levels, action reversibility, and reduced per-step human intervention.$$,$$Explain how an agent plans and takes multi-step action with less per-step approval.$$,$$Understands what changes when a human no longer approves each step.$$,39),
  ('D4','4.11',$$Given a described AI-driven service action an agent can perform, determine the highest safe level of autonomy the agent should be granted.$$,'high','weekly','3_apply',false,$$Bounded autonomy and the factors that set it: reversibility, stakes, confidence, and oversight cost.$$,$$Determine the highest safe autonomy level for a described AI action.$$,$$Grants autonomy only within safe limits.$$,40),
  ('D4','4.12',$$Analyze how errors compound across an agentic workflow's multi-step chain.$$,'high','occasional','4_analyze',false,$$How errors compound across an agentic chain: multi-step failure, blast radius, and the circuit-breaker pattern.$$,$$Analyze where and how a multi-step agentic workflow amplifies an error.$$,$$Anticipates cascade, not just single-step failure.$$,41),
  ('D4','4.13',$$Distinguish human-in-the-loop from human-on-the-loop oversight when applied to AI-driven service actions.$$,'high','weekly','2_understand',false,$$Human-in-the-loop vs human-on-the-loop oversight applied to AI-driven service actions.$$,$$Distinguish the two oversight modes for a service action.$$,$$Chooses real oversight suited to the action.$$,42),
  ('D4','4.14',$$Given a described AI-driven service action, determine an appropriate oversight design for its risk.$$,'high','weekly','3_apply',false,$$Risk-based oversight, oversight design, and what makes a service action consequential.$$,$$Determine an oversight design proportionate to an action's risk.$$,$$Matches oversight strength to consequence.$$,43),
  ('D4','4.15',$$Diagnose why an AI-augmented operation degraded - model drift, data quality, or automation gone wrong.$$,'high','occasional','4_analyze',false,$$Diagnosing a degraded AI operation: model drift, data quality in operations, and automation failure modes.$$,$$Diagnose why an AI-augmented operation degraded.$$,$$Reasons from symptoms to the true cause of degradation.$$,44),
  ('D5','5.1',$$Explain why AI in service management needs governance beyond traditional service controls.$$,'high','weekly','2_understand',false,$$Why AI service actions need governance beyond traditional service controls (autonomy, scale, opacity) and the governance gap.$$,$$Explain what ordinary service controls leave uncovered once AI acts.$$,$$Sees the gap AI opens in traditional controls.$$,45),
  ('D5','5.2',$$Explain accountability when an AI agent takes a service action - who remains answerable.$$,'high','weekly','2_understand',false,$$Agentic accountability, that accountability cannot be delegated to the tool, and meaningful human control.$$,$$Locate who remains answerable when an AI agent takes a service action.$$,$$Refuses to let the tool absorb responsibility.$$,46),
  ('D5','5.3',$$Given an AIOps or predictive pipeline, determine appropriate data-quality and provenance controls.$$,'high','weekly','3_apply',false,$$Data quality for AIOps, data provenance, and garbage-in-garbage-out.$$,$$Determine appropriate data-quality and provenance controls for an AIOps or predictive pipeline.$$,$$Treats data quality as the foundation of AI operations.$$,47),
  ('D5','5.4',$$Explain transparency and disclosure when users interact with AI in a service context.$$,'high','weekly','2_understand',false,$$AI-interaction disclosure, transparency to users, and virtual-agent disclosure.$$,$$Identify the disclosure a service owes users interacting with AI.$$,$$Honest with users about AI's role.$$,48),
  ('D5','5.5',$$Given a described service, determine the over-automation risks and where a human check must remain.$$,'high','weekly','3_apply',false,$$Over-automation risk, automation bias, human-check necessity, and deskilling risk.$$,$$Determine where over-automation risk requires a human check to remain.$$,$$Keeps a human where judgment must not be automated away.$$,49),
  ('D5','5.6',$$Explain how AI service governance connects to the organization's broader AI governance and risk management.$$,'high','occasional','2_understand',false,$$How AI service governance aligns with and links to enterprise AI governance, and defense in depth.$$,$$Connect service-level AI governance to the organization's broader AI risk management.$$,$$Governs in layers, not in isolation.$$,50),
  ('D5','5.7',$$Given a described AI-driven service, determine what to monitor to detect drift, degradation, and harm.$$,'high','weekly','3_apply',false,$$AI service monitoring: what to monitor, drift and degradation signals, and harm-detection signals.$$,$$Determine what to monitor to detect drift, degradation, and harm in an AI service.$$,$$Chooses signals that reveal real harm, not just uptime.$$,51),
  ('D5','5.8',$$Explain how incident-response and continual-improvement processes must adapt when the incident or improvement involves an AI-driven service action.$$,'high','occasional','2_understand',false,$$How incident response and continual improvement must adapt when an AI-driven service action is involved.$$,$$Explain how to feed AI incidents back into improvement.$$,$$Closes the loop from monitoring to improvement.$$,52),
  ('D5','5.9',$$Given an AI service action that caused harm, determine an appropriate escalation and incident path.$$,'high','occasional','3_apply',false,$$The AI service incident (including harm), harm escalation, serious-incident reporting, and rollback and remediation.$$,$$Determine an appropriate escalation and incident path for an AI action that caused harm.$$,$$Routes harm quickly to the right responders.$$,53),
  ('D6','6.1',$$Explain service experience - what it is and why it matters beyond whether a service technically works.$$,'high','weekly','2_understand',false,$$Service experience and why it matters beyond whether a service technically works (perception and value).$$,$$Explain why experience is part of value, not a cosmetic extra.$$,$$Values how a service feels, not only whether it runs.$$,54),
  ('D6','6.2',$$Explain experience-focused measurement - measuring the outcome and satisfaction a user actually gets, not only technical service levels.$$,'high','weekly','2_understand',false,$$Experience measurement, outcome-based metrics, and measuring beyond technical SLAs.$$,$$Explain how to measure the user's actual outcome and satisfaction.$$,$$Measures from the user's side, not only the dashboard.$$,55),
  ('D6','6.3',$$Given a described service situation, determine an action that would improve the user's experience.$$,'high','occasional','3_apply',false,$$Experience improvement, friction identification, and experience-design choices.$$,$$Determine an action that would improve the user's experience.$$,$$Removes friction the user actually feels.$$,56),
  ('D6','6.4',$$Explain trust and adoption as prerequisites for AI-service value - why users must *appropriately* trust and actually adopt an AI service for value to be co-created.$$,'high','weekly','2_understand',false,$$Trust and adoption as prerequisites for AI-service value: appropriate (calibrated) trust and why adoption must be earned.$$,$$Explain why users must appropriately trust and adopt an AI service for value to be co-created.$$,$$Seeks calibrated trust, neither blind nor absent.$$,57),
  ('D6','6.5',$$Given an AI service with low or miscalibrated trust, determine what would build appropriate trust and adoption.$$,'high','weekly','3_apply',false,$$Building appropriate trust through transparency, reliable escalation, and correcting over-trust.$$,$$Determine what would build appropriate trust and adoption for a low- or miscalibrated-trust AI service.$$,$$Designs for trust that is earned and calibrated.$$,58),
  ('D6','6.6',$$Explain sustainable service value - the environmental, social, and economic dimensions woven into the value system.$$,'medium','occasional','2_understand',false,$$Sustainable service value across environmental, social, and economic dimensions, woven into the value system.$$,$$Explain how sustainability is part of how value is created.$$,$$Weighs value across more than the economic dimension.$$,59),
  ('D6','6.7',$$Explain the compute and energy footprint of AI services and why it is a service-management concern.$$,'high','weekly','2_understand',false,$$The compute and energy footprint of AI services and why efficiency is a service-management concern (green AI).$$,$$Explain why an AI service's compute footprint is a service-management matter.$$,$$Treats efficiency as part of service quality.$$,60),
  ('D6','6.8',$$Given an AI service, determine a sustainability-improving action that does not degrade service value.$$,'high','occasional','3_apply',false,$$Sustainability trade-offs, right-sizing models, efficient inference, and preserving the user's outcome.$$,$$Determine a sustainability-improving action that does not degrade service value.$$,$$Cuts footprint without cutting the user's outcome.$$,61)
) as v(domain_code, code, statement, criticality, frequency, bloom, sim, knowledge, skills, abilities, order_index)
join domains d on d.certification_id = '66666666-6666-6666-6666-666666666666' and d.code = v.domain_code;
